			MakeNotificatione("Welcome", "Script access valid! Loading Syncsaken...", 3)
			task.delay(0.5, function()
				local timeLeftSecs = status.data.auth_expire - os.time()
				local hours = math.floor(timeLeftSecs / 3600)
